onClick:
{{
  (async () => {
    const storeVentil = String(appsmith.store.activeVentil || "").trim();

    // Zeilen-Index in den Stammdaten suchen
    const foundIndex = Stammdaten.data.findIndex(r => 
      String(r.Ventil_Links || "").trim() === storeVentil || 
      String(r.Ventil_Rechts || "").trim() === storeVentil
    );

    if (foundIndex === -1) {
      showAlert("Fehler: Ventil wurde nicht in den Stammdaten gefunden!", "error");
      return;
    }

    try {
      // Wir übergeben den Index 37 jetzt direkt an die Query
      await Stammdaten_Update.run({
        targetIndex: foundIndex
      });

      // UI aktualisieren
      await Stammdaten.run(); 
      await Bewaesserung_Lesen.run();

      showAlert("Ventilstatus auf 'Nicht belegt' gesetzt.", "success");
      closeModal('Modal_Programm');
    } catch (e) {
      showAlert("Fehler beim Updaten: " + e.message, "error");
    }
  })()
}}
